	// i=0, nums[0]=0. 0 == 0. Take it. count = 1. Fixed points = 1.
	// i=1, nums[1]=2. 2 != 1. Skip.
	// i=2, nums[2]=1. 1 == 1. Take it. count = 2. Fixed points = 2.
